namespace ReportingApiFunction
{
    public static class QueryReport
    {
        private const string ConnectionString = "<Your_Connection_String>";

        [FunctionName("QueryReport")]
        public static IActionResult Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", Route = "reports/{query}")] HttpRequest req,
            ILogger log)
        {
            log.LogInformation("C# HTTP trigger function processed a request.");

